mapper.select:
SELECT ROUND(NVL(AVG(DISTANCE) / 1000, 0), 2) AS avgDistance, ROUND(NVL(AVG(USAGE_MINUTE), 0), 2) AS avgUsageMinute, ROUND(NVL(SUM(NUM_OF_USES) / NULLIF(COUNT(DISTINCT RENTAL_DATE), 0), 0), 2) AS avgDailyUses, ROUND( NVL( ((SUM(DISTANCE) / 1000) / NULLIF(SUM(USAGE_MINUTE), 0)) * 60, 0 ), 2 ) AS avgSpeed FROM SEOUL_BIKE
AND RENTAL_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND RENTAL_DATE < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
AND UPPER(GENDER) = UPPER(#{gender})
AND RENTAL_CODE = #{rentalCode}
AND RENTAL_OFFICE_NAME = #{keyword}
